        </button>

        {/* ── Right: Breadcrumb + divider + auth ── */}
        <div className="flex items-center gap-3 ml-auto flex-shrink-0">

          {/* Breadcrumb */}
          <nav aria-label="Breadcrumb" className="hidden md:flex items-center gap-1 text-sm">
