              )}
            </div>
          );
        })}
      </nav>

      {/* Footer */}
      <div className="px-4 py-4 border-t border-white/6">
        {user ? (
          <div className="flex items-center gap-2 px-2 py-2 rounded-lg bg-indigo-500/10 border border-indigo-500/20">
