        <SidebarContent />
      </aside>

      {/* Mobile overlay */}
      {mobileOpen && (
        <div className="lg:hidden fixed inset-0 z-40">
          <div className="absolute inset-0 bg-black/50" onClick={onMobileClose} />
          <aside className="relative z-10 flex flex-col w-[260px] h-full bg-[#0a0d14] shadow-2xl">
            <SidebarContent />
          </aside>
        </div>
      )}
    </>
  );
}

